const fs = require('fs');
const path = require('path');

const raw = $input.first().json;
const filePath = (raw.path || '').replace(/\\/g, '/');

// Only process .json files
if (!filePath.endsWith('.json')) return [];

let task;
try {
  const content = fs.readFileSync(filePath, 'utf8').replace(/^\uFEFF/, '');
  task = JSON.parse(content);
} catch(e) {
  return [];
}

// Skip non-PENDING tasks (e.g. already processed on restart)
if ((task.status || '').toUpperCase() !== 'PENDING') return [];

const task_type = (task.task_type || 'CLASSIFY').toUpperCase();

let route, model;
if (task_type === 'RESEARCH') {
  route = 'RESEARCH';
  model = null;
} else if (task_type === 'CODE') {
  route = 'OLLAMA';
  model = 'qwen2.5-coder:7b';
} else if (task_type === 'VISION') {
  route = 'OLLAMA';
  model = 'minicpm-v:8b';
} else {
  // CLASSIFY, SUMMARIZE, COMPRESS, BLUEPRINT, and anything else
  route = 'OLLAMA';
  model = 'qwen3:14b';
}

const vault = 'C:/SFV_BLUEPRINT';

return [{
  json: {
    task_id:      task.task_id || path.basename(filePath, '.json'),
    topic:        task.topic || 'unknown',
    task_type,
    prompt:       task.prompt || '',
    priority:     task.priority || 'NORMAL',
    output_target: (task.output_target || '').replace(/\\/g, '/'),
    file_path:    filePath,
    route,
    model,
    vault
  }
}];

const fs = require('fs');

const BRANCHES = ['MYTHOLOGY','SFV_LIVE','SFV_EVENTS','SFV_ATHLETICS','SFV_STUDIO','SFV_UGC','SFV_ARCHIVE','SFV_WORLD','SFV_404'];

const task = $('Read Task').first().json;
const ollamaOut = $input.first().json;
const response = ollamaOut.response || (ollamaOut.error ? 'ERROR: ' + ollamaOut.error : 'ERROR: Empty response');

const vault = task.vault;
const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);

// Strip <think>...</think> blocks before confidence/validation checks
const responseClean = response.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
const lower = responseClean.toLowerCase();

const LOW_WORDS = ['unsure', 'uncertain', 'not sure', 'unclear', "i don't know", "i'm not sure", 'cannot determine', 'unable to'];
const isLow = LOW_WORDS.some(w => lower.includes(w));
const confidence = isLow ? 'LOW' : 'HIGH';

// Phase 1 validation per OUTPUT_VALIDATION.md
function validate(task_type, text) {
  const words = text.trim().split(/\s+/).filter(Boolean);
  const lc = text.toLowerCase();
  if (task_type === 'CLASSIFY') {
    const branch = BRANCHES.find(b => text.toUpperCase().includes(b));
    if (!branch) return { valid: false, reason: 'No canonical branch name in response' };
    return { valid: true, branch };
  }
  if (task_type === 'SUMMARIZE') {
    if (words.length < 20) return { valid: false, reason: 'Too short: ' + words.length + ' words (min 20)' };
    return { valid: true };
  }
  if (task_type === 'CODE') {
    if (!/\bdef\s+\w+|class\s+\w+/.test(text)) return { valid: false, reason: 'No function or class definition' };
    if (/# TODO:|# fill in here|# implement this/.test(text)) return { valid: false, reason: 'Placeholder code detected' };
    return { valid: true };
  }
  if (task_type === 'VISION') {
    if (words.length < 10) return { valid: false, reason: 'Too short for VISION task' };
    const refusals = ['cannot analyze', 'unable to view', "i can't see", 'not able to view'];
    if (refusals.some(r => lc.includes(r))) return { valid: false, reason: 'VISION refusal detected' };
    return { valid: true };
  }
  if (words.length < 5) return { valid: false, reason: 'Response too short' };
  return { valid: true };
}

let status, outPath, action, handler, validationTag;

if (confidence === 'HIGH') {
  const validation = validate(task.task_type, responseClean);

  if (validation.valid) {
    validationTag = 'VALIDATED';
    const branchLine = validation.branch ? '\nBRANCH: ' + validation.branch : '';
    const outputContent = [
      '---',
      'TASK_ID: ' + task.task_id,
      'DATE: ' + ts,
      'PROCESSED_BY: OLLAMA',
      'STATUS: VALIDATED',
      'REVIEW_REQUIRED: YES' + branchLine,
      '---',
      '',
      '# OUTPUT — ' + task.topic,
      '',
      responseClean,
      ''
    ].join('\n');

    const outputDir = vault + '/99_INBOX/OUTPUTS';
    fs.mkdirSync(outputDir, { recursive: true });
    outPath = task.output_target || (outputDir + '/' + task.task_id + '_RESULT.md');
    fs.writeFileSync(outPath, outputContent, 'utf8');
    status = 'COMPLETE';
    action = 'OLLAMA_' + task.task_type + ' (HIGH CONFIDENCE, VALIDATED)';
    handler = 'OLLAMA';
  } else {
    validationTag = 'ESCALATED';
    const handoff = {
      handoff_id: task.task_id + '-HANDOFF',
      task_type: 'VALIDATION_FAILED',
      priority: task.priority,
      source_task: task.file_path,
      context_budget_tokens: 1500,
      summary: 'Phase 1 validation failed: ' + validation.reason,
      key_findings: [],
      unresolved: [responseClean],
      relevant_files: [],
      do_not_include: [],
      ollama_confidence: 'HIGH',
      escalation_reason: 'Phase 1 validation failed — ' + validation.reason
    };
    const handoffsDir = vault + '/99_INBOX/HANDOFFS';
    fs.mkdirSync(handoffsDir, { recursive: true });
    outPath = handoffsDir + '/' + task.task_id + '_HANDOFF.json';
    fs.writeFileSync(outPath, JSON.stringify(handoff, null, 2), 'utf8');
    status = 'ESCALATED';
    action = 'ESCALATE_VALIDATION_FAIL (' + validation.reason + ')';
    handler = 'CLAUDE';
  }
} else {
  validationTag = 'ESCALATED';
  const handoff = {
    handoff_id: task.task_id + '-HANDOFF',
    task_type: 'REASONING',
    priority: task.priority,
    source_task: task.file_path,
    context_budget_tokens: 1500,
    summary: responseClean.split(/(?<=[.!?])\s+/).slice(0, 3).join(' '),
    key_findings: [],
    unresolved: [responseClean],
    relevant_files: [],
    do_not_include: [],
    ollama_confidence: 'LOW',
    escalation_reason: 'ollama_confidence=LOW — escalated to Claude'
  };
  const handoffsDir = vault + '/99_INBOX/HANDOFFS';
  fs.mkdirSync(handoffsDir, { recursive: true });
  outPath = handoffsDir + '/' + task.task_id + '_HANDOFF.json';
  fs.writeFileSync(outPath, JSON.stringify(handoff, null, 2), 'utf8');
  status = 'ESCALATED';
  action = 'ESCALATE_TO_CLAUDE (LOW CONFIDENCE)';
  handler = 'CLAUDE';
}

const taskData = JSON.parse(fs.readFileSync(task.file_path, 'utf8'));
taskData.status = status;
taskData.processed_at = ts;
taskData.output_written_to = outPath;
fs.writeFileSync(task.file_path, JSON.stringify(taskData, null, 2), 'utf8');

const row = `| ${ts} | ${task.task_id} | ${action} | ${handler} | ${status} | ${outPath.replace(vault, '%VAULT%')} |\n`;
fs.appendFileSync(vault + '/99_INBOX/DECISION_LOG.md', row, 'utf8');

return [{ json: { task_id: task.task_id, topic: task.topic, status, confidence, validation: validationTag, output: outPath } }];

